// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_Q 300005

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->val = val;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

// Function to perform DFS traversal
void dfs(Node* root, int* arr, int* visited, int* stack, int* top, int* balance) {
    if (root == NULL) return;
    visited[root->val] = 1;
    if (arr[root->val] == '(') {
        stack[++(*top)] = root->val;
    } else {
        if (*top > 0) {
            (*top)--;
        } else {
            (*balance) = 0;
        }
    }
    dfs(root->left, arr, visited, stack, top, balance);
    dfs(root->right, arr, visited, stack, top, balance);
}

// Function to check if the path between two nodes is balanced
int isBalanced(int* arr, int u, int v, int* visited, int* stack, int* top, int* balance) {
    *balance = 1;
    *top = 0;
    dfs(createNode(u), arr, visited, stack, top, balance);
    if (*balance == 0) return 0;
    return 1;
}

int main() {
    int T, N, Q, u, v, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &Q);
        int* arr = (int*)malloc(N * sizeof(int));
        int* visited = (int*)malloc(N * sizeof(int));
        int* stack = (int*)malloc(N * sizeof(int));
        int top = 0, balance = 1;
        for (i = 0; i < N; i++) {
            scanf(" %c", &arr[i]);
        }
        for (i = 0; i < Q; i++) {
            scanf("%d %d", &u, &v);
            if (isBalanced(arr, u, v, visited, stack, &top, &balance)) {
                printf("Yes\n");
            } else {
                printf("No\n");
            }
        }
    }
    return 0;
}

