        visited[root.val] = true;
        if (arr[root.val] == '(') {
            stack[++top] = root.val;
        } else {
            if (top > 0) {
                top--;
            } else {
                balance[0] = false;
            }
        }
        for (int child : root.children) {
            dfs(new Node(arr[child]), arr, visited, stack, top, balance);
        }
    }

